using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;/// <summary>/// Good case: Verify consent between two users/// Expected: 200 OK with verification result/// </summary>public class ConsentServiceTests_VerifyConsent_WithValidUsers_ShouldReturnVerification : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "ConsentService"    };    [SkippableFact]    public async Task VerifyConsent_WithValidUsers_ShouldReturnVerification()    {        await AuthenticateAsPatientAsync(ConsentClient);        var request = new         {             patientDid = TestSeedData.PatientUserId.ToString(),             granteeDid = TestSeedData.DoctorUserId.ToString()         };        var response = await PostAsJsonWithRetryAsync(ConsentClient, ApiEndpoints.Consents.Verify, request);        Assert.Equal(HttpStatusCode.OK, response.StatusCode);    }}